VALUES
  ('dietitian-moex-11284', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列對於congestive heart failure（CHF）的飲食建議，何者錯誤？ 使體重稍低於理想體重範圍，以減輕心臟的負擔 提供足夠的蛋白質及礦物質（鈉除外） 盡量以精緻糖取代多醣類 限鈉飲食，通常建議為20～90 mEq', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11285', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關peptic ulcer之敘述，何者正確？ 發生在胃部者通常胃酸分泌均過多  發生在十二指腸者通常胃酸分泌均正常 疼痛常發生在半夜者為十二指腸潰瘍  餐後立即發生疼痛者，為十二指腸潰瘍', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11286', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '針對ulcerative colitis患者應採高熱量高蛋白飲食，但不宜食用下列何種食物？ 清湯  牛奶  肉  蛋', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11287', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '一般常以磺胺類藥物治療區域性腸炎，應特別補充下列何種營養素？ 維生素B  葉酸  維生素B   菸鹼酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11288', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '12', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11289', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關胃分泌消化液的敘述，何者正確？ 胃酸是由胃主細胞所分泌，具有殺菌作用 胃蛋白 是由胃的壁細胞分泌，可分解蛋白質 胃凝乳 可使牛奶之酪蛋白形成凝乳塊 胃黏膜細胞可分泌內在因子，幫助Vit. B 吸收 12', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11290', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以下何者不是肝硬化之症狀？ 食道靜脈曲張    全身性水腫 黃疸（jaundice）    肝門靜脈高血壓', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11291', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關肝炎患者的營養照顧的敘述，何者錯誤？ 若食慾不振和嘔吐，可給予靜脈注射 對活動性肝炎，可採用高熱量高蛋白飲食 對肝炎引起黃疸的患者，不需嚴格限制低油飲食，除非病人對脂肪接受性不佳 治療原則為避免傷害肝細胞，並且使受損肝細胞再生', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11292', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '95％以上的腎病症候群是由下列那三種疾病和症狀所引起？ 糖尿病   紅斑性狼瘡   澱粉樣變性病 高血壓', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11293', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者最不可能是慢性腎衰竭之併發症？ 骨病變  貧血  心血管病變  肝脾腫大', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
